// // This module decrements a 4-bit synchronous counter on each positive edge of the clock signal (clk) and sets it to 15 when the reset signal (rst) is high.
module counter_4bit (
        input clk,
        input rst,
        output reg [3:0] q);

    always @(posedge clk or posedge rst) begin
        if (rst)
            q <= 4'b0000;
        else
            q <= q + 1;
    end

endmodule
